// ─── Servicio API AutoSlot ────────────────────────────────
// Centraliza todas las llamadas al backend Spring Boot (localhost:8080)

import axios from 'axios';

const BASE_URL = 'http://localhost:8080';

const api = axios.create({
  baseURL: BASE_URL,
  headers: { 'Content-Type': 'application/json' },
  timeout: 10000,
});

// ── Interceptor de respuesta para manejo de errores global
api.interceptors.response.use(
  (response) => response,
  (error) => {
    const mensaje = error.response?.data?.message || 'Error de conexión con el servidor';
    return Promise.reject({ ...error, mensaje });
  }
);

// ── USUARIOS ──────────────────────────────────────────────
export const usuarioService = {
  listar:  ()       => api.get('/usuario/listar'),
  crear:   (datos)  => api.post('/usuario/nuevo', datos),
  eliminar:(id)     => api.delete(`/usuario/${id}`),
  actualizar:(id, datos) => api.put(`/usuario/${id}`, datos),
};

// ── DESCUENTOS ────────────────────────────────────────────
export const descuentoService = {
  listar:  ()      => api.get('/descuento/listar'),
  crear:   (datos) => api.post('/descuento/nuevo', datos),
  eliminar:(id)    => api.delete(`/descuento/${id}`),
};

// ── CONVENIOS ─────────────────────────────────────────────
export const convenioService = {
  listar:  ()      => api.get('/convenio/listar'),
  crear:   (datos) => api.post('/convenio/nuevo', datos),
  eliminar:(id)    => api.delete(`/convenio/${id}`),
};

// ── CÁMARAS ───────────────────────────────────────────────
export const camaraService = {
  listar:  ()      => api.get('/camara/listar'),
  crear:   (datos) => api.post('/camara/nuevo', datos),
  eliminar:(id)    => api.delete(`/camara/${id}`),
};

export default api;
